#include <bits/stdc++.h>
using namespace std;
int n,d[10004],val[10004],ti[10004],ans;
vector<int> g[10004];
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        int u,x;
        scanf("%d%d",&u,&ti[i]);
        val[i]=ti[i];
        while(1){
            scanf("%d",&x);
            if(x)
                g[x].push_back(u),d[u]++;
            else
                break;
        }
    }
    queue<int> s,t;
    for(int i=1;i<=n;i++)
        if(!d[i])
            t.push(i);
    while(t.size()){
        s.push(t.front()),t.pop();
        int x=s.back(),len=g[x].size();
        for(int i=0;i<len;i++){
            val[g[x][i]]=max(val[g[x][i]],ti[g[x][i]]+val[x]);
            if(!--d[g[x][i]])
                t.push(g[x][i]);
        }
    }
    for(int i=1;i<=n;i++)
        ans=max(ans,val[i]);
    printf("%d",ans);
    return 0;
}
